object IoTRequests {
    fun deviceBaseUrl(hostOrIp: String, port: Int? = null, https: Boolean = false): HttpUrl {
        val scheme = if (https) "https" else "http"
        val host = hostOrIp.removePrefix("http://").removePrefix("https://").trimEnd('/')
        val builder = HttpUrl.Builder()
            .scheme(scheme)
            .host(host)
            .addPathSegment("")
        if (port != null) builder.port(port)
        return builder.build()
    }

    fun request(
        url: String,
        method: String = "GET",
        headers: Map<String, String> = emptyMap(),
        body: RequestBody? = null
    ): Request {
        val b = Request.Builder().url(url)
        headers.forEach { (k, v) -> b.header(k, v) }
        when (method.uppercase()) {
            "GET" -> b.get()
            "HEAD" -> b.head()
            "POST" -> b.post(body ?: ByteArray(0).toRequestBody(null))
            "PUT" -> b.put(body ?: ByteArray(0).toRequestBody(null))
            "PATCH" -> b.patch(body ?: ByteArray(0).toRequestBody(null))
            "DELETE" -> if (body == null) b.delete() else b.delete(body)
            else -> b.method(method.uppercase(), body)
        }
        return b.build()
    }
}

class CloudAuthInterceptor(
    private val tokenProvider: () -> String?
) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val req = chain.request()
        val token = tokenProvider()
        if (token.isNullOrBlank()) return chain.proceed(req)
        val authed = req.newBuilder()
            .header("Authorization", "Bearer $token")
            .build()
        return chain.proceed(authed)
    }
}

